// agBridgeClient.js - Client-Side SDK for the AG App Local API Bridge

// --- CONFIGURATION ---
// IMPORTANT: This key MUST match the API_KEY constant in your server.js file.
const API_KEY = 'your-secret-api-key-here';
const API_BASE_URL = 'http://localhost:31337';

/**
 * Decodes a base64 string to plain text (UTF-8).
 * Handles both browser (atob) and Node.js (Buffer) environments.
 * @param {string} base64String The base64-encoded string.
 * @returns {string} The decoded plain text.
 */
function decodeBase64(base64String) {
  if (typeof window !== 'undefined' && typeof window.atob === 'function') {
    // Browser environment
    return window.atob(base64String);
  } else if (typeof Buffer !== 'undefined') {
    // Node.js environment
    return Buffer.from(base64String, 'base64').toString('utf-8');
  } else {
    throw new Error('Unable to decode base64 string: No supported environment found (Browser or Node.js).');
  }
}

/**
 * Reads the content of a file from the local file system via the AG Bridge API.
 * @param {string} filePath The absolute path of the file to read.
 * @returns {Promise<string>} A promise that resolves with the plain text content of the file.
 */
async function readFile(filePath) {
  const url = new URL(`${API_BASE_URL}/files`);
  url.searchParams.append('path', filePath);

  try {
    const response = await fetch(url.toString(), {
      method: 'GET',
      headers: {
        'X-API-Key': API_KEY,
      },
    });

    const responseData = await response.json();

    if (!response.ok) {
      // Throw an error with the message from the server's JSON response
      throw new Error(`API Error: ${response.status} ${response.statusText} - ${responseData.message || 'Unknown error'}`);
    }

    // Decode the base64 content and return it
    return decodeBase64(responseData.content);

  } catch (error) {
    // Catches network errors or errors from the check above
    console.error('Failed to read file via AG Bridge:', error);
    throw error; // Re-throw the error to be handled by the caller
  }
}

// Export the function for use in other modules
// This allows you to 'require' it in other Node.js scripts.
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { readFile };
}
