// server.js - Local API Bridge for AG App

const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = 31337;

// --- CONFIGURATION ---
const API_KEY = 'your-secret-api-key-here'; // Match this with your client's key

// --- MIDDLEWARE ---

const apiKeyAuth = (req, res, next) => {
  const providedApiKey = req.get('X-API-Key');
  if (!providedApiKey || providedApiKey !== API_KEY) {
    return res.status(401).json({ message: 'Unauthorized: Missing or invalid API key.' });
  }
  next();
};

app.use(apiKeyAuth);

// --- ROUTES ---

/**
 * GET /files
 * Reads the content of a specified file.
 */
app.get('/files', (req, res) => {
  const filePath = req.query.path;

  if (!filePath) {
    return res.status(400).json({ message: 'Bad Request: Missing required query parameter \\"path\\".' });
  }
  if (!path.isAbsolute(filePath)) {
    return res.status(400).json({ message: 'Bad Request: Path must be absolute.' });
  }

  fs.readFile(filePath, (err, data) => {
    if (err) {
      if (err.code === 'ENOENT') {
        return res.status(404).json({ message: `File not found at path ${filePath}` });
      } else if (err.code === 'EACCES') {
        return res.status(500).json({ message: `Permission denied for file at path ${filePath}` });
      } else {
        console.error('Error reading file:', err);
        return res.status(500).json({ message: 'An unexpected server error occurred.' });
      }
    }
    const base64Content = data.toString('base64');
    res.status(200).json({
      path: filePath,
      content: base64Content,
    });
  });
});

/**
 * GET /directory
 * Reads the contents of a specified directory.
 */
app.get('/directory', (req, res) => {
  const dirPath = req.query.path;

  if (!dirPath) {
    return res.status(400).json({ message: 'Bad Request: Missing required query parameter \\"path\\".' });
  }
  if (!path.isAbsolute(dirPath)) {
    return res.status(400).json({ message: 'Bad Request: Path must be absolute.' });
  }

  fs.readdir(dirPath, { withFileTypes: true }, (err, dirents) => {
    if (err) {
      if (err.code === 'ENOENT') {
        return res.status(404).json({ message: `Directory not found at path ${dirPath}` });
      } else if (err.code === 'ENOTDIR') {
        return res.status(400).json({ message: `Path is not a directory: ${dirPath}` });
      } else {
        console.error('Error reading directory:', err);
        return res.status(500).json({ message: 'An unexpected server error occurred.' });
      }
    }

    const files = [];
    const directories = [];

    for (const dirent of dirents) {
      if (dirent.isDirectory()) {
        directories.push(dirent.name);
      } else {
        files.push(dirent.name);
      }
    }

    res.status(200).json({
      path: dirPath,
      files,
      directories,
    });
  });
});


// --- SERVER INITIALIZATION ---

app.listen(PORT, 'localhost', () => {
  console.log(`AG App Local API Bridge is running on http://localhost:${PORT}`);
  console.log('Endpoints:');
  console.log('  GET /files?path=<absolute_file_path>');
  console.log('  GET /directory?path=<absolute_directory_path>');
  console.log('Awaiting requests with a valid X-API-Key header...');
});
